class Interval:
    def __init__(self, start=0, end=0):
        self.start = start
        self.end = end

def employeeFreeTime(schedule):
    ints = []
    for p in schedule:
        for i in p:
            ints.append((i[0], i[1]))
    ints.sort()
    res, end = [], ints[0][1]
    for i in ints[1:]:
        if i[0] > end:
            res.append([end, i[0]])
        end = max(end, i[1])
    return res

